#### **Model Solution for Q-A (a) — 7 marks**

**Class hierarchy code (full):**

```java
// Abstract base class
public abstract class Component implements java.io.Serializable {
    protected String partNumber;
    protected String description;
    protected int quantity;
    protected double unitCost;
    protected String unitOfMeasure;
    protected int leadTimeDays;
    protected java.util.List<Component> children
            = new java.util.ArrayList<Component>();

    public Component(String pn, String desc, int qty,
                     double cost, String uom, int lead) {
        this.partNumber    = pn;
        this.description   = desc;
        this.quantity      = qty;
        this.unitCost      = cost;
        this.unitOfMeasure = uom;
        this.leadTimeDays  = lead;
    }

    public void addChild(Component c)  { children.add(c); }
    public boolean isLeaf()            { return children.isEmpty(); }

    public double getRolledUpCost() {
        if (isLeaf()) return unitCost * quantity;
        double sum = 0.0;
        for (Component c : children) sum += c.getRolledUpCost();
        return sum;
    }

    public abstract String getCategory();
}

// Concrete Leaf
public class LeafPart extends Component {
    private String manufacturer;
    public LeafPart(String pn, String desc, int qty,
                    double cost, String uom, int lead, String mfg) {
        super(pn, desc, qty, cost, uom, lead);
        this.manufacturer = mfg;
    }
    @Override public String getCategory() { return "LEAF"; }
}

// Concrete Composite
public class Assembly extends Component {
    private String revision;
    public Assembly(String pn, String desc, int qty,
                    double cost, String uom, int lead, String rev) {
        super(pn, desc, qty, cost, uom, lead);
        this.revision = rev;
    }
    @Override public String getCategory() { return "ASSEMBLY"; }
}
```

